public class ReportController : Controller
{
    // Was: protected void btnExport_Click(object sender, EventArgs e)
    [HttpPost]
    public IActionResult Export()
    {
        var data = GenerateReport();

        // Response.Clear(), Response.ContentType, Response.AddHeader,
        // Response.Write, Response.End() are ALL replaced by returning
        // a FileContentResult. ASP.NET Core handles the full response.
        return File(
            System.Text.Encoding.UTF8.GetBytes(data),
            "text/csv",
            "report.csv"
